import{_ as i,o as a,c as e,a2 as t}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"入门路线","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md","lastUpdated":null}'),o={name:"guide/getting-started.md"};function r(n,l,d,h,s,u){return a(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="入门路线" tabindex="-1">入门路线 <a class="header-anchor" href="#入门路线" aria-label="Permalink to &quot;入门路线&quot;">​</a></h1><p>AI 绘画入门最容易卡在两个地方：一是术语太多，二是教程默认你已经知道模型和工作流怎么配。建议按下面顺序学。</p><h2 id="第一步-理解-模型负责什么" tabindex="-1">第一步：理解“模型负责什么” <a class="header-anchor" href="#第一步-理解-模型负责什么" aria-label="Permalink to &quot;第一步：理解“模型负责什么”&quot;">​</a></h2><p>一句话：模型决定图片大方向，提示词和参数只是引导它。</p><p>先弄清楚这些词：</p><ul><li>底模：负责生成能力的核心模型。</li><li>LoRA：给底模临时追加某种角色、画风或概念的小模型。</li><li>VAE：负责把模型内部的潜空间结果转换成可见图片。</li><li>文本编码器：把提示词转成模型能理解的向量。</li></ul><p>如果这些词没区分开，后面很容易把“不兼容”“没加载”“提示词写错”混成一个问题。</p><h2 id="第二步-学会最小出图流程" tabindex="-1">第二步：学会最小出图流程 <a class="header-anchor" href="#第二步-学会最小出图流程" aria-label="Permalink to &quot;第二步：学会最小出图流程&quot;">​</a></h2><p>一个最小的文生图流程通常包括：</p><ol><li>选择底模。</li><li>写正向提示词。</li><li>写负向提示词。</li><li>设置图片尺寸、步数、CFG、采样器。</li><li>运行生成并保存图片。</li></ol><p>先不要急着叠多个 LoRA、ControlNet、高清修复。初学阶段先追求“知道每个改动会造成什么影响”。</p><h2 id="第三步-学会判断模型生态" tabindex="-1">第三步：学会判断模型生态 <a class="header-anchor" href="#第三步-学会判断模型生态" aria-label="Permalink to &quot;第三步：学会判断模型生态&quot;">​</a></h2><p>不同模型不是简单的新旧关系，而是生态不同。</p><ul><li>SD1.5：老生态，资源多，显存要求低，但基础画质和分辨率较旧。</li><li>SDXL：更适合高分辨率和通用画质。</li><li>Pony / Illustrious / NoobAI：偏二次元和标签体系，LoRA 生态强。</li><li>FLUX / Qwen-Image / Z-Image：新一代模型，文字理解和质感更强，但工作流与 LoRA 生态不一定通用。</li></ul><h2 id="第四步-建立自己的工作流" tabindex="-1">第四步：建立自己的工作流 <a class="header-anchor" href="#第四步-建立自己的工作流" aria-label="Permalink to &quot;第四步：建立自己的工作流&quot;">​</a></h2><p>工作流不是玄学配方，而是可复用的节点流程。你应该逐步建立几类基础工作流：</p><ul><li>文生图：从文字生成图片。</li><li>图生图：在原图基础上改风格、改细节。</li><li>局部重绘：只改图片某个区域。</li><li>放大修复：提高分辨率并补细节。</li><li>参考图控制：用参考图影响人物、姿势、风格或构图。</li></ul><h2 id="第五步-再进入进阶主题" tabindex="-1">第五步：再进入进阶主题 <a class="header-anchor" href="#第五步-再进入进阶主题" aria-label="Permalink to &quot;第五步：再进入进阶主题&quot;">​</a></h2><p>当你能稳定理解“为什么这次出图失败”后，再学习：</p><ul><li>LoRA 训练。</li><li>ControlNet 和姿势控制。</li><li>IP-Adapter / 参考图一致性。</li><li>高清修复和分块放大。</li><li>ComfyUI 自定义节点。</li><li>批量生成和自动化。</li></ul><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><ul><li>只换提示词，不换模型。很多风格问题根本不是提示词能解决的。</li><li>乱下 LoRA。LoRA 必须看训练底模，不能假设通用。</li><li>一开始就堆复杂工作流。节点越多，越难定位问题。</li><li>忽略许可证。公开发布作品前，应确认模型、LoRA、素材和平台规则。</li></ul>',22)])])}const _=i(o,[["render",r]]);export{c as __pageData,_ as default};
